  ('fire-eq-tech-moex-01880', 'fire-eq-tech', 'fire-eq-tech-moex-104-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '在長10m、寬8m、高3m之房間燃燒400g氯丁橡膠，其質量光學密度D =0.40m2/g，此時火場中發 m 光避難指標之能見度為多少m？', '["5.217m", "3.253m", "2.475m", "1.957m"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "38e3f80b9c13", "answer_pdf_sha1": "2d8949dd1c15", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "402", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
